sp_angular_provider.script:
/* Use this Directive to add a user picture anywhere in the application
Note: AngularJS normalizes case-sensitive camelCase to case-insensitive kebab-case for the DOM.
Usage in a widget's HTML:
	<dtech-user dtech-user-info="data.userPhotoInfo" ></dtech-user>
	userPhotoInfo is a class with
		sys_id: system id of the user
		photo: photo pulled from avatar in sys_user
		ooo: true false indicator for out of office (when on Task, will show schedule conflict as ooo)
	dtechUserImageSize is the size of the photo to display
		 size: 16,24,32,64

	The HTML for the directive is in	
	templateUrl: getTemplateUrl('x_153465_discovert_dtechUser.html')
//
// Copyrights belong to Discover Technologies LLC. © 2022 Discover Technologies LLC
// Script Continued Below
// 2.8.1 | 2023-01-30 | raj | STRY0135276 - POC - Data Table - Response Comment Update - User Profile Directive - move user profile scripts from TaskWidgetData into UerInfoScitps 
// 2.8.1 | 2023-04-07 | raj | STRY0136617 - Added check for sidebar on and enable chat
// 2.8.1 | 2023-05-11 | mmcc | STRY0139742 - Increase delaying when hover directives open
//  Added CONST_POPOVER_DELAY, d._isClosing, d.initTooltip, d.popoverDelay;
//  In function _init(element) added setting d.popoverDelay = CONST_POPOVER_DELAY;
//  Added function _initTooltip(); in function _leaveTooltip() set d._isClosing = true;
//   Added function _popoverDelay(); in function _showDuration(event) set d._isClosing = false;
//										   
*/
function dtechUser(getTemplateUrl, spModal, $timeout, $window) {
	var CONST_TEMP_WAIT_DURATION = 600;

	// 2.8.1 | 2023-05-11 | mmcc | STRY0139742 - Increase delaying when hover directives open; TODO: get from a service
	var CONST_POPOVER_DELAY = 1200;

	var dtUser = {
		restrict: 'E',
		replace: true,
		// @: string 1 way, =: object 2 way, <: object 1 way
		scope: {
			dtechChatEnabled: "<", // STRY0136617
			dtechField: "<",
			dtechTaskTitle: "<?",
			dtechUserImageSize: '<',
			dtechUserPhotoInfo: '=', 
			dtechParamObject: '=', 
			dtechUserToolTipOpen: "=?",
			dtechIsModal: "=",
			parentSysId: "<",
			table: "<"
		},
		controller: userCtrl,
		link: link,
		controllerAs: 'd',
		templateUrl: getTemplateUrl('x_153465_discovert_dtechUser.html')
	};
	return dtUser;

	function userCtrl($scope, $attrs, dtechOrganizationalUser, $animate) {
		var d = this;
		// STRY0136617
		d.chatEnabled = _chatEnabled;
		d._isOverTooltip = false;

		// 2.8.1 | 2023-05-11 | mmcc | STRY0139742 - Increase delaying when hover directives open; added, init to false
		d._isClosing = false;

		d.dtechParamObject = _dtechParamObject;
		d.dtechTaskTitle = _dtechTaskTitle;
		d.dtechUserImageSize = _dtechUserImageSize;
		d.dtechUserPhotoInfo = _dtechUserPhotoInfo;
		d.dtechUserToolTipOpen = _dtechUserToolTipOpen;
		d.enterTooltip = _enterTooltip;
		d.init = _init;

		// 2.8.1 | 2023-05-11 | mmcc | STRY0139742 - Increase delaying when hover directives open; added
		d.initTooltip = _initTooltip;

		d.isSpinnerShown = false;
		d.leaveTooltip = _leaveTooltip;
		d.openColabChatConversation = _openColabChatConversation;
		d.openModal= _openModal;
		d.openUserProfileModal= _openUserProfileModal;
		d.parentMouseLeave = _parentMouseLeave;

		// 2.8.1 | 2023-05-11 | mmcc | STRY0139742 - Increase delaying when hover directives open; added to set popover-popup-delay in the HTML
		d.popoverDelay = _popoverDelay;

		d.sendMailTo = _sendMailTo;
		d.setStyleBackgroundImage = _setStyleBackgroundImage;
		d.showProfile = _showProfile;

		// STRY0136617
		function _chatEnabled() {
			return $scope.dtechChatEnabled;
		}

		function _openColabChatConversation(){
			alert("Comming sooon... Sidebar colab chat");
		}

		function _dtechUserImageSize(){
			return $scope.dtechUserImageSize;
		}

		function _dtechUserPhotoInfo(){
			return $scope.dtechUserPhotoInfo;
		}

		function _dtechParamObject(){
			return $scope.dtechParamObject;
		}

		function _dtechTaskTitle(value){
			return $scope.dtechTaskTitle;
		}

		function _dtechUserToolTipOpen(){
			return $scope.dtechUserToolTipOpen;
		}

		// when the user hovers over the tooltip set overtooltip flag
		function _enterTooltip(){
			d._isOverTooltip = true;
		}

		// init()
		// initialize the control, called from the Link function
		// gets a reference to the element
		function _init(element) {
			d.$element = element;

			$scope.dtechUserToolTipOpen = 
				angular.isDefined($attrs.dtechUserToolTipOpen) ?
				$scope.$parent.$eval($attrs.dtechUserToolTipOpen) : false;

			// 2.8.1 | 2023-05-11 | mmcc | STRY0139742 - Increase delaying when hover directives open; set to const
			d.popoverDelay = CONST_POPOVER_DELAY;
		}

		// 2.8.1 | 2023-05-11 | mmcc | STRY0139742 - Increase delaying when hover directives open; added function
		function _initTooltip() {
			// if the user moved off of the parent before the tooltip opened, cancel the open
			if (d._isClosing == true) {
				_leaveTooltip();
				// d._isClosing = false;
			}
		}

		function _leaveTooltip(){
			d._isOverTooltip = false;
			$scope.dtechUserToolTipOpen = false;

			// 2.8.1 | 2023-05-11 | mmcc | STRY0139742 - Increase delaying when hover directives open; set true
			d._isClosing = true;
		}

		// openModal()
		// this function is called from Template html
		// it is called when a user clicks on the Open User Profile link
		function _openModal(event) {
			var title = '';
			if($scope.table=='x_153465_discovert_route_task_instance' &&
				$scope.dtechField=="assigned_to" ||
				$scope.dtechField=="u_reviewer" ||
				$scope.dtechField=="u_task_requester"){
				title = "${Tasker - Title - Assignment Modal}" + 
					$scope.dtechTaskTitle;
				x_153465_discovert.twJS.openAssignmentModal(
					spModal, title, $scope.table, $scope.parentSysId);
				// modal is openened stop the row or cell click form raising
				event.stopPropagation();
			} else {
				_openUserProfileModal(event);
			}
		}

		function _openUserProfileModal(event){
			var title = 'Tasker User Settings Container';
			var widget = 'tasker_user_settings_container';
			spModal.open({
				title: title,
				backdrop: 'static',
				widget: widget,
				widgetInput: {
					sys_id: $scope.dtechUserPhotoInfo.sys_id,
					isModal: true
				},
				size: 'lg',
				buttons: [],
				footerStyle: {
					'display': 'none'
				}
			});
			// modal is openened stop the row or cell click form raising
			event.stopPropagation();
		}

		// _parentMouseLeave
		// this is the get function for the direcitve property parentMouseLeave
		// this function is called when the user hovers off the profile image
		function _parentMouseLeave(){
			$timeout(function() {
				if(!d._isOverTooltip){
					d.leaveTooltip();
				}
			}, CONST_TEMP_WAIT_DURATION);
		}

		// 2.8.1 | 2023-05-11 | mmcc | STRY0139742 - Increase delaying when hover directives open; added function
		function _popoverDelay() {
			return d.popoverDelay;
		}

		// sendMailTo()
		// this function is called from Template html
		// it is called when a user clicks on the link to send an email to a user
		function _sendMailTo() {
			var emailData = 'mailto:' + $scope.dtechParamObject.email;
			if ($scope.dtechParamObject && $scope.dtechParamObject.emailSubject && $scope.dtechParamObject.emailSubject.length > 0) {
				emailData = emailData + '?subject=' + $scope.dtechParamObject.emailSubject;
			}
			$window.open(emailData, '_self');
		}	

		// Returns a string to set a style tag over in the Macro HTML to display a persons' photo
		// Parameter photo is sys_user avatar field with .iix?t=small appended
		function  _setStyleBackgroundImage(photo) {
			var imageUrl = '';

			if (photo != undefined) {
				imageUrl = "background-image: url('" + photo + "');";
			} else {
				imageUrl = "background-image: url('Profile16.svg');";
			}

			return imageUrl;
		}

		function _showProfile(event){
			// reset over tooltip to false when tooltip opens
			var _isOverTooltip = false;
			var userId = "";
			var photo = "";
			var name = "";
			var photoInfo = $scope.dtechUserPhotoInfo;
			var userProfile = $scope.dtechParamObject;

			// 2.8.1 | 2023-05-11 | mmcc | STRY0139742 - Increase delaying when hover directives open; set false
			d._isClosing = false;

			if(photoInfo){
				userId = photoInfo.sys_id;
				photo = photoInfo.photo;
				name = photoInfo.name;
			}
			if(!userProfile){
				userProfile = {};
				userProfile.sys_id = userId;
				userProfile.photo = photo;
				userProfile.name =name;
				userProfile.loaded = false;
			}
			if(!userProfile.loaded){
				// load profile
				d.isSpinnerShown = true;
				dtechOrganizationalUser.getUserProfile(
					$scope.dtechParamObject.sys_id).then(
					function(response){
						$scope.dtechParamObject = response.userProfile;
						$scope.dtechParamObject.photoBackground =
							d.setStyleBackgroundImage($scope.dtechParamObject.photo);
						d.isSpinnerShown = false;
						$scope.dtechParamObject.loaded = true;
					});

			}
			$scope.dtechParamObject=userProfile;
			$scope.dtechUserToolTipOpen = true;
		}
	}

	// Link function links local methods to parent controller methods
	// see the list of events being monitored
	function link(scope, element, attrs, userCtrl){
		// initialize the control
		userCtrl.init(element);			
		scope.$on('$destroy',_destroy);
		// get the location of the element hovering over

		function _destroy(){
			element.remove();
		}
	}

}
